import html
import json

from .douyin_monitor import serialize_log


def create_interactive_report(session):
    report = serialize_log(session)
    payload = json.dumps(report, ensure_ascii=False).replace('<', '\\u003c')
    title = html.escape(session.room_title or '未获取')
    douyin_id = html.escape(session.douyin_id)
    document = r'''<!doctype html>
<html lang="zh-CN"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1">
<title>__TITLE__ - 实时在线人数曲线</title>
<style>
:root{font-family:"Microsoft YaHei UI","Microsoft YaHei",sans-serif;color:#2d2020;background:#f8f4f1}*{box-sizing:border-box}body{margin:0;padding:32px}.report{max-width:1180px;margin:auto}.head,.panel{background:#fff;border:1px solid rgba(63,39,39,.16)}.head{padding:26px 30px;margin-bottom:18px}.head h1{margin:0 0 10px;font-family:SimSun,serif;font-weight:400}.meta{display:flex;flex-wrap:wrap;gap:10px 28px;color:#756967;font-size:13px}.panel{padding:24px}.toolbar{display:flex;align-items:center;justify-content:space-between;gap:16px}.toolbar h2{font-size:17px}.switch{display:flex;border:1px solid #d8cbc7}.switch button{border:0;border-right:1px solid #d8cbc7;padding:9px 14px;background:#fff;color:#756967;cursor:pointer}.switch button:last-child{border-right:0}.switch button.active{color:#fff;background:#5a262a}.hint{color:#887b78;font-size:12px}.chart{position:relative;height:500px;border:1px solid #eee5e1;background:#fff;overflow:hidden}.chart svg{display:block;width:100%;height:100%}.tooltip{position:absolute;min-width:140px;padding:9px 11px;color:#fff;background:rgba(45,32,32,.94);font-size:12px;line-height:1.6;pointer-events:none;transform:translate(-50%,-115%)}.summary{display:grid;grid-template-columns:repeat(4,1fr);gap:12px;margin-top:14px}.metric{padding:14px;background:#f4ece8}.metric small{display:block;color:#8a7c79;font-size:11px}.metric strong{display:block;margin-top:5px;font-size:18px}.alert-history{margin-top:26px;padding-top:22px;border-top:1px solid #e4d9d5}.alert-heading{display:flex;align-items:center;justify-content:space-between;gap:16px;padding:12px 14px;border:1px solid #e4d9d5;background:#faf7f5;cursor:pointer;list-style:none}.alert-heading::-webkit-details-marker{display:none}.alert-heading h3{margin:0;font-size:16px}.alert-heading-right{display:flex;align-items:center;gap:18px;color:#887b78;font-size:12px}.alert-toggle::before{content:"展开明细";color:#5a262a}.alert-history[open] .alert-toggle::before{content:"收起明细"}.alert-history[open] .alert-heading{margin-bottom:12px}.alert-list{max-height:480px;overflow:auto}.alert-table{width:100%;border-collapse:collapse;font-size:13px}.alert-table th,.alert-table td{padding:13px 15px;border:1px solid #e5dcd8;text-align:left}.alert-table th{position:sticky;top:0;z-index:1;background:#f4ece8;color:#746764;font-size:11px;font-weight:600}.alert-table td:first-child{width:72px;color:#8a7c79}.alert-table td:last-child{font-weight:600}.alert-empty{padding:28px;border:1px dashed #d8cbc7;color:#928682;font-size:13px;text-align:center}.empty{height:100%;display:grid;place-items:center;color:#928682}@media(max-width:720px){body{padding:12px}.toolbar{align-items:flex-start;flex-direction:column}.switch{width:100%;overflow:auto}.chart{height:390px}.summary{grid-template-columns:1fr 1fr}.alert-heading{align-items:flex-start}.alert-heading-right{align-items:flex-end;flex-direction:column;gap:5px}.alert-table th,.alert-table td{padding:11px 9px}.alert-table td:first-child{width:50px}}
</style></head><body><main class="report">
<section class="head"><h1>抖音直播间实时在线人数曲线</h1><div class="meta"><span>直播间：__TITLE__</span><span>抖音号：__DOUYIN__</span><span id="time-range"></span></div></section>
<section class="panel"><div class="toolbar"><h2>在线人数变化</h2><div class="switch"><button class="active" data-minutes="5">每5分钟</button><button data-minutes="15">每15分钟</button><button data-minutes="30">每30分钟</button><button data-minutes="60">每1小时</button></div></div><p class="hint" id="hint"></p><div class="chart" id="chart"></div><div class="summary"><div class="metric"><small>最低在线</small><strong id="minimum">--</strong></div><div class="metric"><small>最高在线</small><strong id="maximum">--</strong></div><div class="metric"><small>记录点数</small><strong id="point-count">--</strong></div><div class="metric"><small>告警次数</small><strong id="alert-count">--</strong></div></div><details class="alert-history"><summary class="alert-heading"><h3>告警时间点</h3><span class="alert-heading-right"><span id="alert-total"></span><span class="alert-toggle"></span></span></summary><div class="alert-list" id="alert-list"></div></details></section>
</main><script>
const report=__REPORT__,chart=document.getElementById('chart');
const full=t=>{if(!t)return'监控中';const d=new Date(t);return d.getFullYear()+'/'+(d.getMonth()+1)+'/'+d.getDate()+' '+String(d.getHours()).padStart(2,'0')+':'+String(d.getMinutes()).padStart(2,'0')+':'+String(d.getSeconds()).padStart(2,'0')};
const tick=t=>{const d=new Date(t),s=new Date(report.startedAt),c=String(d.getHours()).padStart(2,'0')+':'+String(d.getMinutes()).padStart(2,'0');return d.toDateString()===s.toDateString()?c:(d.getMonth()+1)+'/'+d.getDate()+' '+c};
const alertEvents=[...(report.alerts||[])].sort((a,b)=>a.time-b.time),alertList=document.getElementById('alert-list');document.getElementById('time-range').textContent='监控时间：'+full(report.startedAt)+' 至 '+full(report.endedAt);document.getElementById('alert-count').textContent=alertEvents.length+'次';document.getElementById('alert-total').textContent='共 '+alertEvents.length+' 次';if(!alertEvents.length){alertList.innerHTML='<div class="alert-empty">暂无告警记录</div>'}else{alertList.innerHTML='<table class="alert-table"><thead><tr><th>序号</th><th>告警时间</th><th>时间点在线人数</th></tr></thead><tbody>'+alertEvents.map((event,index)=>'<tr><td>'+(index+1)+'</td><td>'+full(event.time)+'</td><td>'+Number(event.count||0).toLocaleString('zh-CN')+' 人</td></tr>').join('')+'</tbody></table>'}
function sample(minutes){const raw=[...(report.points||[])].sort((a,b)=>a.time-b.time);if(!raw.length)return[];const gap=minutes*60000,start=report.startedAt,out=[{time:start,count:raw[0].count}];let next=start+gap;for(const p of raw){if(p.time<next)continue;const boundary=start+Math.floor((p.time-start)/gap)*gap;out.push({time:boundary,count:p.count});next=boundary+gap}if(report.endedAt&&raw.at(-1).time>out.at(-1).time)out.push({time:report.endedAt,count:raw.at(-1).count});return out}
function render(minutes){const points=sample(minutes);document.getElementById('hint').textContent='当前按'+(minutes===60?'每1小时':'每'+minutes+'分钟')+'记录点展示，鼠标移到曲线上可查看具体数据。';if(!points.length){chart.innerHTML='<div class="empty">该日志暂无在线人数数据</div>';return}const width=1080,height=500,m={left:78,right:24,top:28,bottom:58},pw=width-m.left-m.right,ph=height-m.top-m.bottom,counts=points.map(p=>p.count),max=Math.max(5,...counts),step=Math.max(1,Math.ceil(max/5/10)*10),ymax=step*5,start=report.startedAt,gap=minutes*60000,end=Math.max(report.endedAt||points.at(-1).time,start+gap),finish=start+Math.max(1,Math.ceil((end-start)/gap))*gap,x=t=>m.left+(t-start)/(finish-start)*pw,y=c=>m.top+ph-c/ymax*ph,path=points.map((p,i)=>(i?'L':'M')+' '+x(p.time).toFixed(2)+' '+y(p.count).toFixed(2)).join(' '),slots=Math.max(1,Math.round((finish-start)/gap)),stride=Math.max(1,Math.ceil(slots/8)),xt=[];for(let i=0;i<=slots;i+=stride)xt.push(start+i*gap);if(xt.at(-1)!==finish)xt.push(finish);const yt=Array.from({length:6},(_,i)=>step*i),alerts=(report.alerts||[]).filter(a=>a.time>=start&&a.time<=finish);chart.innerHTML='<svg viewBox="0 0 '+width+' '+height+'" preserveAspectRatio="none">'+yt.map(v=>'<line x1="'+m.left+'" y1="'+y(v)+'" x2="'+(width-m.right)+'" y2="'+y(v)+'" stroke="#eee5e1"/><text x="'+(m.left-10)+'" y="'+(y(v)+4)+'" text-anchor="end" fill="#817572" font-size="11">'+v.toLocaleString('zh-CN')+'人</text>').join('')+xt.map(t=>'<line x1="'+x(t)+'" y1="'+m.top+'" x2="'+x(t)+'" y2="'+(m.top+ph)+'" stroke="#f4eeeb"/><text x="'+x(t)+'" y="'+(height-25)+'" text-anchor="middle" fill="#817572" font-size="10">'+tick(t)+'</text>').join('')+alerts.map(a=>'<line x1="'+x(a.time)+'" y1="'+m.top+'" x2="'+x(a.time)+'" y2="'+(m.top+ph)+'" stroke="#b77b37" stroke-dasharray="5 5"/>').join('')+'<path d="'+path+'" fill="none" stroke="#5a262a" stroke-width="3" stroke-linecap="round" stroke-linejoin="round"/><line class="hover" visibility="hidden" y1="'+m.top+'" y2="'+(m.top+ph)+'" stroke="#80726f" stroke-dasharray="4 4"/><circle class="dot" visibility="hidden" r="5" fill="#fff" stroke="#5a262a" stroke-width="3"/><rect class="hit" x="'+m.left+'" y="'+m.top+'" width="'+pw+'" height="'+ph+'" fill="transparent"/></svg><div class="tooltip" hidden></div>';document.getElementById('minimum').textContent=Math.min(...counts).toLocaleString('zh-CN')+'人';document.getElementById('maximum').textContent=Math.max(...counts).toLocaleString('zh-CN')+'人';document.getElementById('point-count').textContent=points.length+'个';const svg=chart.querySelector('svg'),hit=chart.querySelector('.hit'),line=chart.querySelector('.hover'),dot=chart.querySelector('.dot'),tip=chart.querySelector('.tooltip');hit.onmousemove=e=>{const rect=svg.getBoundingClientRect(),sx=(e.clientX-rect.left)/rect.width*width,target=start+(sx-m.left)/pw*(finish-start);let p=points[0];for(const item of points)if(Math.abs(item.time-target)<Math.abs(p.time-target))p=item;const px=x(p.time),py=y(p.count);line.setAttribute('x1',px);line.setAttribute('x2',px);line.setAttribute('visibility','visible');dot.setAttribute('cx',px);dot.setAttribute('cy',py);dot.setAttribute('visibility','visible');tip.hidden=false;tip.innerHTML=full(p.time)+'<br><b>'+p.count.toLocaleString('zh-CN')+'人</b>';tip.style.left=px/width*100+'%';tip.style.top=py/height*100+'%'};hit.onmouseleave=()=>{line.setAttribute('visibility','hidden');dot.setAttribute('visibility','hidden');tip.hidden=true}}
document.querySelectorAll('.switch button').forEach(button=>button.onclick=()=>{document.querySelectorAll('.switch button').forEach(item=>item.classList.toggle('active',item===button));render(Number(button.dataset.minutes))});render(5);
</script></body></html>'''
    return (
        document.replace('__TITLE__', title)
        .replace('__DOUYIN__', douyin_id)
        .replace('__REPORT__', payload)
    )
